function solve(m, n, waitCost) {
    const dp = new Array(m).fill().map(() => new Array(n).fill().map(() => [Infinity, Infinity]));
    dp[0][0][1] = (0 + 1) * (0 + 1); // initial cost at step 1 (odd)

    const directions = [[1, 0], [0, 1]]; // down and right

    for (let step = 1; step <= 2 * m * n; step++) {
        const isOddStep = step % 2 === 1;
        const newDp = new Array(m).fill().map(() => new Array(n).fill().map(() => [Infinity, Infinity]));

        for (let i = 0; i < m; i++) {
            for (let j = 0; j < n; j++) {
                for (const prevState of [0, 1]) {
                    if (dp[i][j][prevState] === Infinity) continue;

                    if (isOddStep) {
                        for (const [di, dj] of directions) {
                            const ni = i + di;
                            const nj = j + dj;
                            if (ni < m && nj < n) {
                                const cost = (ni + 1) * (nj + 1);
                                newDp[ni][nj][1] = Math.min(newDp[ni][nj][1], dp[i][j][prevState] + cost);
                            }
                        }
                    } else {
                        const cost = waitCost[i][j];
                        newDp[i][j][0] = Math.min(newDp[i][j][0], dp[i][j][prevState] + cost);
                    }
                }
            }
        }

        for (let i = 0; i < m; i++) {
            for (let j = 0; j < n; j++) {
                for (const state of [0, 1]) {
                    dp[i][j][state] = Math.min(dp[i][j][state], newDp[i][j][state]);
                }
            }
        }
    }

    return Math.min(dp[m - 1][n - 1][0], dp[m - 1][n - 1][1]);
}

